{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "user_id": "$upstream.fetch_iam_role.user_id",
        "permission": "$upstream.fetch_iam_role.permission",
        "resource": "$upstream.fetch_iam_role.resource",
        "action": "$upstream.fetch_iam_role.action"
      },
      "depends_on": []
    },
    {
      "tool": "mongo.find",
      "arguments": {
        "collection": "workflow_approvals",
        "filter": {
          "user_id": "$upstream.fetch_iam_role.user_id",
          "approval_type": "manager_approval",
          "status": { "$in": ["approved", "pending", "rejected"] }
        },
        "projection": {
          "workflow_id": 1,
          "approver_id": 1,
          "approval_status": 1,
          "approved_at": 1,
          "requested_role": 1,
          "metadata": 1
        }
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT workflow_id, requested_permission, requested_resource, requested_action, approval_status, manager_id, created_at, updated_at FROM workflow_metadata WHERE user_id = '$upstream.fetch_iam_role.user_id' ORDER BY created_at DESC LIMIT 1"
      },
      "depends_on": [1]
    },
    {
      "tool": "iam.grant_role",
      "arguments": {
        "user_id": "$upstream.fetch_iam_role.user_id",
        "role": "$2.results.requested_role",
        "resource": "$upstream.fetch_iam_role.resource",
        "approved_by": "$2.results.approver_id",
        "workflow_id": "$2.results.workflow_id",
        "condition": {
          "approval_status_check": "$2.results.approval_status",
          "required_status": "approved"
        }
      },
      "depends_on": [2, 3]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "iam.grant_role",
        "performed_by": "orchestration_system",
        "target_user_id": "$upstream.fetch_iam_role.user_id",
        "role_granted": "$2.results.requested_role",
        "resource": "$upstream.fetch_iam_role.resource",
        "workflow_id": "$2.results.workflow_id",
        "approver_id": "$2.results.approver_id",
        "approval_status": "$2.results.approval_status",
        "iam_check_result": "$1.result",
        "timestamp": "$4.granted_at",
        "metadata": {
          "snowflake_workflow_record": "$3.results",
          "mongo_approval_record": "$2.results"
        }
      },
      "depends_on": [4]

